import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"How the Engine Works","description":"","frontmatter":{},"headers":[],"relativePath":"engine/how-it-works.md","filePath":"engine/how-it-works.md"}'),l={name:"engine/how-it-works.md"};function c(n,e,s,r,d,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="how-the-engine-works" tabindex="-1">How the Engine Works <a class="header-anchor" href="#how-the-engine-works" aria-label="Permalink to &quot;How the Engine Works&quot;">​</a></h1><h2 id="pipeline" tabindex="-1">Pipeline <a class="header-anchor" href="#pipeline" aria-label="Permalink to &quot;Pipeline&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Source Code → Compile → Launch JVM → Attach JDI → Step → Capture → Normalize → UEF</span></span></code></pre></div><h3 id="_1-compile" tabindex="-1">1. Compile <a class="header-anchor" href="#_1-compile" aria-label="Permalink to &quot;1. Compile&quot;">​</a></h3><p>Uses <code>javax.tools.JavaCompiler</code> to compile source code to <code>.class</code> files in a temp directory.</p><h3 id="_2-launch" tabindex="-1">2. Launch <a class="header-anchor" href="#_2-launch" aria-label="Permalink to &quot;2. Launch&quot;">​</a></h3><p>Creates a new JVM process via JDI <code>LaunchingConnector</code>. The JVM starts with the debugger attached from the beginning.</p><h3 id="_3-attach-jdi-events" tabindex="-1">3. Attach JDI Events <a class="header-anchor" href="#_3-attach-jdi-events" aria-label="Permalink to &quot;3. Attach JDI Events&quot;">​</a></h3><p>Subscribes to:</p><ul><li><code>ClassPrepareEvent</code> — know when user class is loaded</li><li><code>StepEvent</code> — line-by-line stepping</li><li><code>MethodEntryEvent</code> / <code>MethodExitEvent</code> — track call stack</li><li><code>ExceptionEvent</code> — capture thrown exceptions</li></ul><h3 id="_4-capture-state" tabindex="-1">4. Capture State <a class="header-anchor" href="#_4-capture-state" aria-label="Permalink to &quot;4. Capture State&quot;">​</a></h3><p>At every step, the engine inspects:</p><ul><li>All stack frames via <code>ThreadReference.frames()</code></li><li>Local variables via <code>StackFrame.visibleVariables()</code></li><li>Object fields via <code>ObjectReference.getValue()</code></li><li>Array elements via <code>ArrayReference.getValues()</code></li></ul><h3 id="_5-normalize" tabindex="-1">5. Normalize <a class="header-anchor" href="#_5-normalize" aria-label="Permalink to &quot;5. Normalize&quot;">​</a></h3><p>Raw JDI types are converted to UEF value kinds:</p><ul><li><code>IntegerValue</code> → <code>{ &quot;kind&quot;: &quot;primitive&quot;, &quot;type&quot;: &quot;int&quot;, &quot;value&quot;: 42 }</code></li><li><code>ArrayReference</code> → stored in heap as <code>HeapObject.ArrayInstance</code></li><li><code>ObjectReference</code> → stored in heap as <code>HeapObject.ObjectInstance</code></li><li><code>null</code> → <code>{ &quot;kind&quot;: &quot;null&quot; }</code></li></ul><h3 id="_6-compute-deltas" tabindex="-1">6. Compute Deltas <a class="header-anchor" href="#_6-compute-deltas" aria-label="Permalink to &quot;6. Compute Deltas&quot;">​</a></h3><p>Previous state is compared to current state:</p><ul><li>New locals → <code>FrameChange</code> with <code>before: null</code></li><li>Changed locals → <code>FrameChange</code> with before/after values</li><li>Changed fields → <code>HeapChange</code> with object ID and path</li><li>New heap objects → classified as <code>OBJECT_ALLOCATED</code></li></ul><h3 id="_7-classify-event" tabindex="-1">7. Classify Event <a class="header-anchor" href="#_7-classify-event" aria-label="Permalink to &quot;7. Classify Event&quot;">​</a></h3><p>Based on what changed:</p><ul><li>New heap objects → <code>OBJECT_ALLOCATED</code></li><li>Changed fields → <code>FIELD_UPDATED</code></li><li>Changed array elements → <code>ARRAY_ELEMENT_UPDATED</code></li><li>Changed locals → <code>VARIABLE_ASSIGNED</code></li><li>Nothing changed → <code>LINE_CHANGED</code></li></ul><h3 id="_8-serialize-uef" tabindex="-1">8. Serialize UEF <a class="header-anchor" href="#_8-serialize-uef" aria-label="Permalink to &quot;8. Serialize UEF&quot;">​</a></h3><p>Complete trace assembled with session metadata, recording context, all steps, and diagnostics. Serialized to JSON via custom Jackson serializers.</p>',24)])])}const m=a(l,[["render",c]]);export{p as __pageData,m as default};
